];

export async function getAllProducts() {
  // Simulate database read latency
  await new Promise(resolve => setTimeout(resolve, 80));
  return products;
}

export async function updateProductPrice(sku, newPrice) {
  await new Promise(resolve => setTimeout(resolve, 50));
  products = products.map(p =>
    p.sku === sku ? { ...p, price: newPrice, lastSyncedAt: new Date().toISOString() } : p
  );
}

export async function updateProductInventory(sku, delta) {
  await new Promise(resolve => setTimeout(resolve, 50));
  products = products.map(p =>
    p.sku === sku
      ? { ...p, inventory: Math.max(0, p.inventory + delta), lastSyncedAt: new Date().toISOString() }
      : p
  );
}

export async function applySyncBatch(upstreamData) {
  // Simulate batch-writing upstream changes to the DB
  await new Promise(resolve => setTimeout(resolve, 200));
  products = upstreamData.map(p => ({ ...p, lastSyncedAt: new Date().toISOString() }));
}

