import { unstable_cache } from 'next/cache';
import { getAllProducts } from '@/lib/db';
import type { Product } from '@/types/product';

/**
 * Returns the full product catalog, cached under the "products" tag.
 *
 * The cache is NOT time-based — it only expires when the "products" tag
 * is revalidated via `revalidateTag('products', 'max')` (triggered by
 * the admin sync action). This keeps the read-heavy catalog fast while
 * still allowing explicit cache busting after an upstream sync.
 */
export const getCachedProducts = unstable_cache(
  async (): Promise<Product[]> => {
    const raw = await getAllProducts();
    // The db mock already returns well-shaped data, but in a real app
    // this is where you'd normalise / transform before caching.
    return raw as Product[];
  },
  ['catalog-all-products'],
  {
    tags: ['products'],
    /**
     * `revalidate: false` means the cache entry lives until explicitly
     * invalidated via `revalidateTag('products', …)`.  No stale-while-
     * revalidate window.
     */
    revalidate: false,
  }
);

import { applySyncBatch, getAllProducts } from '@/lib/db';

/**
 * Simulates a full catalog sync from an upstream ERP/PIM system.
 *
 * In production this would:
 *   1. Call an external PIM/ERP API to fetch latest pricing & inventory
 *   2. Transform/normalise the data into the local schema
 *   3. Batch-write the results to the local DB
 *   4. Call `revalidateTag('products', 'max')` to bust the Next.js cache
 *
 * The caller is responsible for calling `revalidateTag` after this
 * completes — this function only mutates the backing data store.
 */
export async function performCatalogSync(): Promise<void> {
  // Simulate network latency to upstream ERP/PIM
  await new Promise(resolve => setTimeout(resolve, 3_000));

  const current = await getAllProducts();

  // Simulate upstream changes — adjust prices & inventory as if
  // the ERP pushed new data.
  const upstream = current.map((p) => {
    const priceAdjust = 1 + (Math.random() - 0.5) * 0.1; // ±5%
    return {
      ...p,
      price: Math.round(p.price * priceAdjust),
      inventory: Math.max(0, p.inventory + Math.floor((Math.random() - 0.5) * 20)),
      status: p.status === 'discontinued' ? 'discontinued' as const : 'active' as const,
    };
  });

  await applySyncBatch(upstream);

  // In a production system, after the DB write succeeds you'd
  // optionally push a revalidation event through a message queue
  // so multiple app instances all bust their caches.
}

'use client';

import { useActionState } from 'react';
import { useFormStatus } from 'react-dom';
import type { ComponentProps } from 'react';

/* ------------------------------------------------------------------ */
/*  Types                                                             */
/* ------------------------------------------------------------------ */

export type SyncState = {
  success: boolean;
  message: string;
};

type SyncAction = (
  prevState: SyncState | null,
  formData: FormData
) => Promise<SyncState>;

/* ------------------------------------------------------------------ */
/*  Submit button – reads pending state from the nearest <form>        */
/* ------------------------------------------------------------------ */

function SubmitButton() {
  const { pending } = useFormStatus();

  return (
    <button
      type="submit"
      disabled={pending}
      className={
        'sync-btn' +
        (pending ? ' sync-btn--pending' : '')
      }
    >
      {pending ? '⏳ Syncing…' : '↻  Sync Latest Catalog'}
    </button>
  );
}

/* ------------------------------------------------------------------ */
/*  SyncForm                                                          */
/* ------------------------------------------------------------------ */

type SyncFormProps = {
  action: SyncAction;
} & Omit<ComponentProps<'form'>, 'action'>;

export function SyncForm({ action, ...formProps }: SyncFormProps) {
  const [state, formAction] = useActionState(action, null);

  return (
    <form action={formAction} {...formProps}>
      <SubmitButton />

      {state?.success === true && (
        <p className="sync-feedback sync-feedback--ok">{state.message}</p>
      )}
      {state?.success === false && (
        <p className="sync-feedback sync-feedback--err" role="alert">
          {state.message || 'Sync failed. Please try again.'}
        </p>
      )}
    </form>
  );
}

'use client';

import type { Product } from '@/types/product';

/* ------------------------------------------------------------------ */
/*  Helpers                                                            */
/* ------------------------------------------------------------------ */

const statusLabel: Record<Product['status'], string> = {
  active: 'Active',
  inactive: 'Inactive',
  discontinued: 'Discontinued',
};

const statusClass: Record<Product['status'], string> = {
  active: 'badge badge--active',
  inactive: 'badge badge--inactive',
  discontinued: 'badge badge--discontinued',
};

function formatCurrency(amount: number): string {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
  }).format(amount);
}

function formatTimestamp(iso: string): string {
  return new Intl.DateTimeFormat('en-US', {
    dateStyle: 'medium',
    timeStyle: 'short',
  }).format(new Date(iso));
}

/* ------------------------------------------------------------------ */
/*  Empty state                                                        */
/* ------------------------------------------------------------------ */

function EmptyState() {
  return (
    <div className="empty-state">
      <p>No products found in the catalog.</p>
      <p className="empty-state--hint">
        Try triggering a <strong>Sync Latest Catalog</strong> to pull
        product data from the upstream ERP/PIM.
      </p>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Table                                                              */
/* ------------------------------------------------------------------ */

type CatalogTableProps = {
  products: Product[];
};

export function CatalogTable({ products }: CatalogTableProps) {
  if (products.length === 0) {
    return <EmptyState />;
  }

  return (
    <div className="table-wrapper">
      <table className="catalog-table">
        <thead>
          <tr>
            <th>SKU</th>
            <th>Name</th>
            <th>Price</th>
            <th>Inventory</th>
            <th>Status</th>
            <th>Last Synced</th>
          </tr>
        </thead>
        <tbody>
          {products.map((p) => (
            <tr key={p.id}>
              <td className="cell-sku">{p.sku}</td>
              <td>{p.name}</td>
              <td className="cell-price">{formatCurrency(p.price)}</td>
              <td className="cell-inventory">
                {p.inventory === 0 ? (
                  <span className="no-stock">Out of stock</span>
                ) : (
                  p.inventory
                )}
              </td>
              <td>
                <span className={statusClass[p.status]}>
                  {statusLabel[p.status]}
                </span>
              </td>
              <td className="cell-timestamp">{formatTimestamp(p.lastSyncedAt)}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

import { revalidateTag } from 'next/cache';
import { after } from 'next/server';
import { getCachedProducts } from '@/lib/products';
import { performCatalogSync } from '@/lib/sync';
import { CatalogTable } from '@/components/admin/catalog-table';
import { SyncForm } from '@/components/admin/sync-form';
import type { SyncState } from '@/components/admin/sync-form';

/* ------------------------------------------------------------------ */
/*  Metadata                                                           */
/* ------------------------------------------------------------------ */

export const metadata = {
  title: 'Catalog — Admin',
};

/* ------------------------------------------------------------------ */
/*  Inline Server Action — sync trigger                                */
/* ------------------------------------------------------------------ */

/**
 * Triggered by the "Sync Latest Catalog" form submission.
 *
 * Design decisions
 * ----------------
 * 1. **Fire-and-forget via `after()`** — the action returns immediately
 *    so the admin can keep browsing while the sync runs in the background.
 *    Product data is briefly stale, which is acceptable for the admin use
 *    case (operators prefer a responsive UI over blocking on fresh data).
 *
 * 2. **Tag-based cache invalidation** — once the sync completes, the
 *    `"products"` cache tag is fully expired. Any subsequent page render
 *    that reads through `getCachedProducts` (wrapped with `unstable_cache`
 *    and tagged `"products"`) will fetch fresh data from the DB.
 *
 * 3. **Eventual consistency** — because all catalog views use the same
 *    cache tag, invalidating `"products"` guarantees consistency across
 *    the entire admin surface once the cache is repopulated.
 */
async function syncCatalog(
  _prevState: SyncState | null,
  _formData: FormData
): Promise<SyncState> {
  'use server';

  try {
    // Schedule the sync to run after the response is sent.
    // The admin sees the success message immediately and can continue
    // working. The product list may be briefly stale.
    after(async () => {
      await performCatalogSync();
      // Fully expire all cache entries tagged "products" so the next
      // page load fetches fresh data from the DB.
      revalidateTag('products', 'max');
    });

    return {
      success: true,
      message:
        'Catalog sync started — changes will appear across all catalog views shortly.',
    };
  } catch (err) {
    console.error('Catalog sync failed:', err);
    return {
      success: false,
      message:
        err instanceof Error
          ? err.message
          : 'An unexpected error occurred while syncing the catalog.',
    };
  }
}

/* ------------------------------------------------------------------ */
/*  Page component                                                     */
/* ------------------------------------------------------------------ */

export default async function CatalogPage() {
  const products = await getCachedProducts();

  return (
    <main className="catalog-page">
      <header className="catalog-header">
        <div>
          <h1>Product Catalog</h1>
          <p className="catalog-subtitle">
            {products.length} product{products.length !== 1 ? 's' : ''} —
            <span className="catalog-note">
              {' '}prices & inventory are cached; run a sync to refresh
            </span>
          </p>
        </div>

        <SyncForm action={syncCatalog} />
      </header>

      <CatalogTable products={products} />
    </main>
  );
}

export default function AdminLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  return <>{children}</>;
}

/* =================================================================
