  font-weight: 500;
}

.cell-inventory {
  font-variant-numeric: tabular-nums;
}

.cell-timestamp {
  font-size: 0.8125rem;
  color: #5a5d72;
  white-space: nowrap;
}

.no-stock {
  color: #b91c1c;
  font-weight: 500;
  font-size: 0.8125rem;
}

/* --- Status badges ------------------------------------------------- */

.badge {
  display: inline-block;
  padding: 0.125rem 0.5rem;
  border-radius: 999px;
  font-size: 0.75rem;
  font-weight: 550;
  letter-spacing: 0.01em;
}

.badge--active {
  background: #e6f7ee;
  color: #0d6832;
}

.badge--inactive {
  background: #fff3e0;
  color: #914600;
}

.badge--discontinued {
  background: #fce8e8;
  color: #991b1b;
}

/* --- Sync form ----------------------------------------------------- */

.sync-btn {
  display: inline-flex;
  align-items: center;
  gap: 0.375rem;
  padding: 0.5rem 1rem;
  border: 1px solid #cbd5e1;
  border-radius: 6px;
  background: #fff;
  color: #1e293b;
  font-size: 0.875rem;
  font-weight: 500;
  cursor: pointer;
  transition: background 0.15s, border-color 0.15s, box-shadow 0.15s;
  white-space: nowrap;
}

.sync-btn:hover:not(:disabled) {
  background: #f1f5f9;
  border-color: #94a3b8;
}

.sync-btn:focus-visible {
  outline: 2px solid #2563eb;
  outline-offset: 2px;
}

.sync-btn:disabled {
  opacity: 0.6;
  cursor: not-allowed;
}

.sync-btn--pending {
  background: #f1f5f9;
  border-color: #94a3b8;
}

.sync-feedback {
  margin: 0.5rem 0 0;
  font-size: 0.8125rem;
}

.sync-feedback--ok {
  color: #0d6832;
}

.sync-feedback--err {
  color: #991b1b;
}

/* --- Empty state --------------------------------------------------- */

.empty-state {
  text-align: center;
  padding: 3rem 1.5rem;
  border: 1px dashed #cbd5e1;
  border-radius: 8px;
  background: #fff;
  color: #5a5d72;
}

.empty-state--hint {
  font-size: 0.875rem;
  margin-top: 0.25rem;
}

